<body>
    <div class="container">
        <h1>Live String Reverser</h1>

        <div class="input-group">
            <label for="textInput">Type some text:</label>
            <input type="text" id="textInput" placeholder="Start typing here..." autofocus>
        </div>

        <div class="output-section">
            <span id="reversedOutput"></span>
        </div>

        <div class="footer">
            <p>Built with ❤️ for real-time fun!</p>
        </div>
    </div>

    <script>
        const textInput = document.getElementById('textInput');
        const reversedOutput = document.getElementById('reversedOutput');

        // Store the previous reversed string to compare for animations
        let previousReversedText = '';

        function reverseString(str) {
            return str.split('').reverse().join('');
        }

        function updateReversedOutput() {
            const inputText = textInput.value;
            const currentReversedText = reverseString(inputText);

            // Get the current characters in the output (if any)
            const oldChars = Array.from(reversedOutput.children);
            const newChars = currentReversedText.split('');

            // Clear existing content to prepare for re-rendering with animations
            reversedOutput.innerHTML = '';

            // This is where the character-by-character animation logic comes in
            newChars.forEach((char, index) => {
                const span = document.createElement('span');
                span.textContent = char;

                // Determine animation class
                let animationClass = '';
                if (index < oldChars.length) {
                    // Character at this position existed before
                    const oldChar = oldChars[index].textContent;
                    if (oldChar !== char) {
                        // Character changed at this position
                        animationClass = 'animate-change';
                    }
                    // If it's the same, no specific animation class needed,
                    // it will just transition smoothly due to span's default transition.
                } else {
                    // New character added
                    animationClass = 'animate-in';
                }

                if (animationClass) {
                    span.classList.add(animationClass);
                    // Remove the animation class after it completes to allow re-animation
                    span.addEventListener('animationend', () => {
                        span.classList.remove(animationClass);
                    }, { once: true });
                }

                reversedOutput.appendChild(span);
            });

            // If the new string is shorter, the "extra" old characters are implicitly removed
            // by clearing innerHTML and rebuilding. We could add an explicit 'animate-out'
            // for these, but it makes the logic more complex and rebuilding is often sufficient.
            // For this project, rebuilding with the new set of characters is cleaner.

            previousReversedText = currentReversedText;
        }

        // Initial update on load
        updateReversedOutput();

        // Listen for input changes in real-time
        textInput.addEventListener('input', updateReversedOutput);
    </script>
</body>
</html>
