            // Mark old elements for exit animation if they are no longer needed
            oldElements.forEach((oldEl, oldIndex) => {
                const oldChar = oldEl.querySelector('span').textContent;
                const newChar = newReversedChars[oldIndex];

                // If the character at this position has changed or is gone
                if (oldChar !== newChar || oldIndex >= newReversedChars.length) {
                    oldEl.classList.add('exiting');
